const { ethers } = require('ethers');

const ERC20_ABI = [
  'function balanceOf(address) view returns (uint256)',
  'function decimals() view returns (uint8)',
  'function symbol() view returns (string)'
];

function pick(input, ...keys) {
  for (const key of keys) {
    if (input[key] !== undefined && input[key] !== null && input[key] !== '') return input[key];
  }
  return undefined;
}

async function getBalance(input = {}) {
  const rpcUrl = pick(input, 'rpc_url', 'rpcUrl', 'RPC_URL') || process.env.RPC_URL;
  const tokenAddress = pick(input, 'token_address', 'tokenAddress');
  const walletAddress = pick(input, 'wallet_address', 'walletAddress');

  if (!rpcUrl) throw new Error('RPC_URL or rpc_url is required');
  if (!tokenAddress) throw new Error('token_address is required');
  if (!walletAddress) throw new Error('wallet_address is required');

  const provider = new ethers.providers.JsonRpcProvider(rpcUrl);
  const token = new ethers.Contract(tokenAddress, ERC20_ABI, provider);
  const [balance, decimals, symbol] = await Promise.all([
    token.balanceOf(walletAddress),
    token.decimals(),
    token.symbol()
  ]);

  return {
    raw: balance.toString(),
    formatted: ethers.utils.formatUnits(balance, decimals),
    symbol,
    decimals
  };
}

module.exports = { getBalance };

const { ethers } = require('ethers');

const ERC20_ABI = [
  'function transfer(address to, uint256 amount) returns (bool)',
  'function decimals() view returns (uint8)'
];

function pick(input, ...keys) {
  for (const key of keys) {
    if (input[key] !== undefined && input[key] !== null && input[key] !== '') return input[key];
  }
  return undefined;
}

async function transfer(input = {}) {
  const rpcUrl = pick(input, 'rpc_url', 'rpcUrl', 'RPC_URL') || process.env.RPC_URL;
  const privateKey = pick(input, 'private_key', 'privateKey', 'PRIVATE_KEY') || process.env.PRIVATE_KEY;
  const tokenAddress = pick(input, 'token_address', 'tokenAddress');
  const to = pick(input, 'to');
  const amount = pick(input, 'amount');

  if (!rpcUrl) throw new Error('RPC_URL or rpc_url is required');
  if (!privateKey) throw new Error('PRIVATE_KEY or private_key is required');
  if (!tokenAddress) throw new Error('token_address is required');
  if (!to) throw new Error('to is required');
  if (amount === undefined || amount === null || amount === '') throw new Error('amount is required');

  const provider = new ethers.providers.JsonRpcProvider(rpcUrl);
  const wallet = new ethers.Wallet(privateKey, provider);
  const token = new ethers.Contract(tokenAddress, ERC20_ABI, wallet);
  const decimals = await token.decimals();
  const tx = await token.transfer(to, ethers.utils.parseUnits(String(amount), decimals));
  const receipt = await tx.wait();

  return {
    tx_hash: receipt.transactionHash,
    status: receipt.status === 1 ? 'success' : 'failed'
  };
}

module.exports = { transfer };

